/**
 * Notification dropdown panel — attaches to the Bell icon in the header.
 * Shows recent notifications with priority indicators and mark-as-read.
 */
import { useState, useEffect, useCallback, useMemo, useRef } from "react";
import {
  Bell,
  Check,
  CheckCheck,
  AlertTriangle,
  Clock,
  Info,
  X,
} from "lucide-react";
import { Button } from "../ui/Button.js";
import { Badge } from "../ui/Badge.js";
import { useHostBridge } from "../../host/HostProvider.js";
import { createApiClient } from "../../api/client.js";
import {
  createNotificationApi,
  type NotificationResponse,
  type PagedNotificationResponse,
} from "../../api/notificationApi.js";

// ── Priority icon + color mapping ───────────────────────────────────────────

const PRIORITY_CONFIG = {
  HIGH: { icon: AlertTriangle, className: "text-foreground", bgClassName: "bg-foreground/10" },
  MEDIUM: { icon: Clock, className: "text-muted", bgClassName: "bg-neutral-100" },
  LOW: { icon: Info, className: "text-muted", bgClassName: "bg-surface-raised" },
} as const;

function timeAgo(iso: string): string {
  const diff = Date.now() - new Date(iso).getTime();
  const mins = Math.floor(diff / 60_000);
  if (mins < 1) return "just now";
  if (mins < 60) return `${mins}m ago`;
  const hours = Math.floor(mins / 60);
  if (hours < 24) return `${hours}h ago`;
  const days = Math.floor(hours / 24);
  return `${days}d ago`;
}

// ── NotificationPanel ───────────────────────────────────────────────────────

export function NotificationPanel() {
  const bridge = useHostBridge();
  const { authToken, authenticatedUser } = bridge.context;

  const api = useMemo(() => {
    const client = createApiClient({
      baseUrl: "/api",
      getAuthToken: () => bridge.context.authToken,
    });
    return createNotificationApi(client, authenticatedUser.id);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [authToken, authenticatedUser.id]);

  const [open, setOpen] = useState(false);
  const [data, setData] = useState<PagedNotificationResponse | null>(null);
  const [loading, setLoading] = useState(false);
  const panelRef = useRef<HTMLDivElement>(null);

  // Fetch notifications on open + periodic refresh
  const fetchNotifications = useCallback(async () => {
    setLoading(true);
    try {
      const result = await api.list(1, 15);
      setData(result);
    } catch {
      // silently fail — notification panel is non-critical
    } finally {
      setLoading(false);
    }
  }, [api]);

  // Fetch unread count on mount for badge
  useEffect(() => {
    void fetchNotifications();
    const interval = setInterval(() => void fetchNotifications(), 30_000);
    return () => clearInterval(interval);
  }, [fetchNotifications]);

  // Fetch full list when opening
  useEffect(() => {
    if (open) void fetchNotifications();
  }, [open, fetchNotifications]);

  // Close on outside click
  useEffect(() => {
    if (!open) return;
    function handleClick(e: MouseEvent) {
      if (panelRef.current && !panelRef.current.contains(e.target as Node)) {
        setOpen(false);
      }
    }
    document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, [open]);

  const handleMarkRead = useCallback(
    async (id: string) => {
      try {
        await api.markAsRead(id);
        setData((prev) => {
          if (!prev) return prev;
          return {
            ...prev,
            unreadCount: Math.max(0, prev.unreadCount - 1),
            items: prev.items.map((n) => (n.id === id ? { ...n, read: true } : n)),
          };
        });
      } catch {
        // ignore
      }
    },
    [api],
  );

  const handleMarkAllRead = useCallback(async () => {
    try {
      await api.markAllAsRead();
      setData((prev) => {
        if (!prev) return prev;
        return {
          ...prev,
          unreadCount: 0,
          items: prev.items.map((n) => ({ ...n, read: true })),
        };
      });
    } catch {
      // ignore
    }
  }, [api]);

  const unreadCount = data?.unreadCount ?? 0;

  return (
    <div ref={panelRef} className="relative" data-testid="notification-panel">
      {/* Bell button */}
      <Button
        variant="ghost"
        size="icon"
        aria-label={`Notifications${unreadCount > 0 ? ` (${unreadCount} unread)` : ""}`}
        className="relative"
        onClick={() => setOpen(!open)}
        data-testid="notification-bell"
      >
        <Bell className="h-4 w-4" />
        {unreadCount > 0 && (
          <span
            className="absolute -right-0.5 -top-0.5 flex h-4 min-w-4 items-center justify-center rounded-full bg-foreground px-1 text-[9px] font-bold text-background"
            data-testid="notification-badge"
          >
            {unreadCount > 99 ? "99+" : unreadCount}
          </span>
        )}
      </Button>

      {/* Dropdown panel */}
      {open && (
        <div
          className="absolute right-0 top-full mt-2 w-96 max-h-[28rem] overflow-hidden rounded-lg border border-border bg-surface shadow-lg z-50 flex flex-col"
          role="dialog"
          aria-label="Notifications"
          data-testid="notification-dropdown"
        >
          {/* Header */}
          <div className="flex items-center justify-between border-b border-border px-4 py-2.5">
            <h3 className="text-sm font-semibold">Notifications</h3>
            <div className="flex items-center gap-2">
              {unreadCount > 0 && (
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => void handleMarkAllRead()}
                  className="text-xs"
                  data-testid="mark-all-read-btn"
                >
                  <CheckCheck className="h-3 w-3 mr-1" /> Mark all read
                </Button>
              )}
              <Button
                variant="ghost"
                size="icon"
                onClick={() => setOpen(false)}
                aria-label="Close notifications"
              >
                <X className="h-3.5 w-3.5" />
              </Button>
            </div>
          </div>

          {/* List */}
          <div className="flex-1 overflow-y-auto">
            {loading && !data && (
              <p className="p-4 text-sm text-muted animate-pulse">Loading…</p>
            )}
            {data && data.items.length === 0 && (
              <div className="p-8 text-center text-sm text-muted">
                <Bell className="h-8 w-8 mx-auto mb-2 opacity-30" />
                No notifications yet
              </div>
            )}
            {data?.items.map((notif) => (
              <NotificationItem
                key={notif.id}
                notification={notif}
                onMarkRead={handleMarkRead}
              />
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

// ── Single notification item ────────────────────────────────────────────────

function NotificationItem({
  notification,
  onMarkRead,
}: {
  readonly notification: NotificationResponse;
  readonly onMarkRead: (id: string) => void;
}) {
  const priorityCfg = PRIORITY_CONFIG[notification.priority] ?? PRIORITY_CONFIG.LOW;
  const Icon = priorityCfg.icon;

  return (
    <div
      className={`flex gap-3 px-4 py-3 border-b border-border/50 transition-colors ${
        notification.read ? "opacity-60" : "bg-primary/[0.02]"
      }`}
      data-testid={`notification-item-${notification.id}`}
    >
      {/* Priority icon */}
      <div className={`shrink-0 mt-0.5 rounded-full p-1.5 ${priorityCfg.bgClassName}`}>
        <Icon className={`h-3.5 w-3.5 ${priorityCfg.className}`} />
      </div>

      {/* Content */}
      <div className="flex-1 min-w-0">
        <p className={`text-sm leading-snug ${notification.read ? "" : "font-medium"}`}>
          {notification.title}
        </p>
        <p className="text-xs text-muted mt-0.5 line-clamp-2">{notification.body}</p>
        <div className="flex items-center gap-2 mt-1">
          <span className="text-[10px] text-muted">{timeAgo(notification.createdAt)}</span>
          <Badge
            variant={notification.priority === "HIGH" ? "locked" : "draft"}
            className="text-[9px] px-1.5 py-0"
          >
            {notification.priority}
          </Badge>
        </div>
      </div>

      {/* Mark read button */}
      {!notification.read && (
        <button
          type="button"
          onClick={() => onMarkRead(notification.id)}
          className="shrink-0 mt-0.5 rounded-full p-1 hover:bg-surface-raised transition-colors"
          aria-label="Mark as read"
          data-testid={`mark-read-${notification.id}`}
        >
          <Check className="h-3.5 w-3.5 text-muted" />
        </button>
      )}
    </div>
  );
}

/**
 * OverviewSection — top-level team week summary cards.
 */
import { cn } from "../../lib/utils.js";
import type { MemberComplianceSummary, MemberWeekView, ExceptionResponse, ExceptionSeverity } from "../../api/teamTypes.js";

export interface OverviewSectionProps {
  readonly complianceSummary: MemberComplianceSummary[];
  readonly memberViews: MemberWeekView[];
  readonly exceptions: ExceptionResponse[];
}

function ComplianceCard({ label, compliantCount, totalCount, testId }: { label: string; compliantCount: number; totalCount: number; testId: string }) {
  const pct = totalCount > 0 ? Math.round((compliantCount / totalCount) * 100) : 100;
  const valueCls = pct >= 80 ? "text-foreground" : pct >= 50 ? "text-muted" : "text-foreground font-black underline";

  return (
    <div data-testid={testId} className="rounded-default border border-border bg-surface p-4 flex-1 min-w-[180px]">
      <div className="text-[0.7rem] text-muted font-semibold uppercase tracking-wider mb-2">{label}</div>
      <div className={cn("text-2xl font-bold", valueCls)} data-testid={`${testId}-count`}>{compliantCount}/{totalCount}</div>
      <div className="text-xs text-muted mt-1" data-testid={`${testId}-pct`}>{pct}% on-time</div>
    </div>
  );
}

function PointsCard({ plannedPoints, achievedPoints }: { plannedPoints: number; achievedPoints: number }) {
  const delta = achievedPoints - plannedPoints;
  return (
    <div data-testid="points-summary-card" className="rounded-default border border-border bg-surface p-4 flex-1 min-w-[180px]">
      <div className="text-[0.7rem] text-muted font-semibold uppercase tracking-wider mb-2">Points</div>
      <div className="flex gap-4 items-baseline flex-wrap">
        <div>
          <span className="text-2xl font-bold" data-testid="planned-points">{plannedPoints}</span>
          <span className="text-xs text-muted ml-1">planned</span>
        </div>
        <div>
          <span className={cn("text-2xl font-bold", achievedPoints > 0 ? "text-foreground" : "text-muted")} data-testid="achieved-points">{achievedPoints}</span>
          <span className="text-xs text-muted ml-1">achieved</span>
        </div>
      </div>
      {achievedPoints > 0 && (
        <div className={cn("text-xs mt-1 font-semibold", delta >= 0 ? "text-foreground" : "text-foreground underline")} data-testid="points-delta">
          {delta >= 0 ? "+" : ""}{delta} delta
        </div>
      )}
    </div>
  );
}

const SEVERITY_BADGE: Record<ExceptionSeverity, string> = {
  HIGH: "bg-foreground text-background",
  MEDIUM: "bg-neutral-400 text-background",
  LOW: "bg-neutral-200 text-neutral-700",
};

function ExceptionsCard({ exceptions }: { exceptions: ExceptionResponse[] }) {
  const open = exceptions.filter((e) => !e.resolved);
  const highCount = open.filter((e) => e.severity === "HIGH").length;
  const medCount = open.filter((e) => e.severity === "MEDIUM").length;
  const lowCount = open.filter((e) => e.severity === "LOW").length;

  return (
    <div data-testid="exceptions-overview-card" className="rounded-default border border-border bg-surface p-4 flex-1 min-w-[180px]">
      <div className="text-[0.7rem] text-muted font-semibold uppercase tracking-wider mb-2">Open Exceptions</div>
      <div className={cn("text-2xl font-bold", open.length > 0 ? "text-foreground underline" : "text-foreground")} data-testid="open-exceptions-count">{open.length}</div>
      {open.length > 0 && (
        <div className="flex gap-1.5 mt-2 flex-wrap">
          {highCount > 0 && <span data-testid="exceptions-high-count" className={cn("text-[0.65rem] font-bold px-1.5 py-px rounded-full", SEVERITY_BADGE.HIGH)}>{highCount} HIGH</span>}
          {medCount > 0 && <span data-testid="exceptions-medium-count" className={cn("text-[0.65rem] font-bold px-1.5 py-px rounded-full", SEVERITY_BADGE.MEDIUM)}>{medCount} MED</span>}
          {lowCount > 0 && <span data-testid="exceptions-low-count" className={cn("text-[0.65rem] font-bold px-1.5 py-px rounded-full", SEVERITY_BADGE.LOW)}>{lowCount} LOW</span>}
        </div>
      )}
    </div>
  );
}

export function OverviewSection({ complianceSummary, memberViews, exceptions }: OverviewSectionProps) {
  const total = complianceSummary.length;
  const lockedCount = complianceSummary.filter((m) => m.lockCompliant).length;
  const reconciledCount = complianceSummary.filter((m) => m.reconcileCompliant).length;
  const plannedPoints = memberViews.reduce((sum, m) => sum + m.totalCommittedPoints, 0);
  const achievedPoints = memberViews.reduce((sum, m) => sum + m.commits.filter((c) => c.outcome === "ACHIEVED").reduce((s, c) => s + (c.estimatePoints ?? 0), 0), 0);

  return (
    <section aria-labelledby="overview-heading" data-testid="overview-section">
      <h3 id="overview-heading" className="m-0 mb-3 text-sm font-bold">Overview</h3>
      <div className="flex gap-3 flex-wrap">
        <ComplianceCard label="Lock Compliance" compliantCount={lockedCount} totalCount={total} testId="lock-compliance-card" />
        <ComplianceCard label="Reconcile Compliance" compliantCount={reconciledCount} totalCount={total} testId="reconcile-compliance-card" />
        <PointsCard plannedPoints={plannedPoints} achievedPoints={achievedPoints} />
        <ExceptionsCard exceptions={exceptions} />
      </div>
    </section>
  );
}

/**
 * Lightweight data-fetching hooks following a useQuery pattern.
 * Wraps the API client with loading and error state management.
 */

import { useState, useEffect, useCallback, useRef } from "react";
import { ApiRequestError } from "./client.js";

export interface QueryState<T> {
  readonly data: T | undefined;
  readonly loading: boolean;
  readonly error: ApiRequestError | null;
  /** Re-trigger the query. */
  refetch(): void;
}

/**
 * Executes an async fetcher and manages loading/error/data state.
 * Re-runs whenever the `key` string changes.
 *
 * @param key     Cache/identity key. Change it to re-run the query.
 * @param fetcher Async function returning the data.
 */
export function useQuery<T>(
  key: string,
  fetcher: () => Promise<T>,
  options?: { enabled?: boolean },
): QueryState<T> {
  const [data, setData] = useState<T | undefined>(undefined);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<ApiRequestError | null>(null);
  const [revision, setRevision] = useState(0);
  const enabled = options?.enabled ?? true;

  // Keep a stable ref to the fetcher so the effect dep array stays clean
  const fetcherRef = useRef(fetcher);
  fetcherRef.current = fetcher;

  useEffect(() => {
    if (!enabled) {
      setData(undefined);
      setLoading(false);
      setError(null);
      return;
    }

    let cancelled = false;
    setLoading(true);
    setError(null);

    fetcherRef
      .current()
      .then((result) => {
        if (!cancelled) {
          setData(result);
          setLoading(false);
        }
      })
      .catch((err: unknown) => {
        if (!cancelled) {
          if (err instanceof ApiRequestError) {
            setError(err);
          } else {
            setError(
              new ApiRequestError({ status: 0, message: "Unexpected error" }),
            );
          }
          setLoading(false);
        }
      });

    return () => {
      cancelled = true;
    };
  }, [enabled, key, revision]);

  const refetch = useCallback(() => {
    setRevision((r) => r + 1);
  }, []);

  return { data, loading, error, refetch };
}

