/**
 * React hooks for RAG (Retrieval-Augmented Generation) API endpoints.
 */
import { useCallback, useMemo, useState } from "react";
import { useHostBridge } from "../host/HostProvider.js";
import { createApiClient } from "./client.js";
import { useQuery, type QueryState } from "./hooks.js";
import {
  createRagApi,
  type InsightListResponse,
  type RagApi,
  type RagQueryResponse,
} from "./ragApi.js";

// ── Base hook ─────────────────────────────────────────────────────────────────

/** Returns a stable {@link RagApi} instance bound to the current user. */
export function useRagApi(): RagApi {
  const bridge = useHostBridge();
  const { authToken, authenticatedUser } = bridge.context;
  return useMemo(() => {
    const client = createApiClient({
      baseUrl: "/api",
      getAuthToken: () => bridge.context.authToken,
    });
    return createRagApi(client, authenticatedUser.id);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [authToken, authenticatedUser.id]);
}

// ── Query hooks ───────────────────────────────────────────────────────────────

/**
 * Fetches TEAM_INSIGHT cards for the given team and week.
 *
 * @param teamId    team UUID string, or {@code null} to skip fetching
 * @param weekStart ISO date string (YYYY-MM-DD) for the Monday of the target week
 */
export function useTeamInsights(
  teamId: string | null,
  weekStart: string,
): QueryState<InsightListResponse> {
  const api = useRagApi();
  return useQuery<InsightListResponse>(
    `team-insights-${teamId ?? "none"}-${weekStart}`,
    () => {
      if (!teamId) return Promise.reject(new Error("No team ID"));
      return api.getTeamInsights(teamId, weekStart);
    },
    { enabled: teamId != null },
  );
}

/**
 * Fetches PERSONAL_INSIGHT cards for the given plan.
 *
 * @param planId plan UUID string, or {@code null} to skip fetching
 */
export function usePlanInsights(
  planId: string | null,
): QueryState<InsightListResponse> {
  const api = useRagApi();
  return useQuery<InsightListResponse>(
    `plan-insights-${planId ?? "none"}`,
    () => {
      if (!planId) return Promise.reject(new Error("No plan ID"));
      return api.getPlanInsights(planId);
    },
    { enabled: planId != null },
  );
}

// ── Mutation hook ─────────────────────────────────────────────────────────────

export interface SemanticQueryState {
  /** Executes the RAG query. */
  mutate: (question: string, teamId?: string, userId?: string) => Promise<void>;
  /** The most recent query response; {@code undefined} before first call. */
  data: RagQueryResponse | undefined;
  /** {@code true} while a query is in-flight. */
  loading: boolean;
  /** Error message if the last query failed. */
  error: string | null;
}

/**
 * Mutation hook for submitting a semantic RAG query.
 *
 * @example
 * ```tsx
 * const { mutate, data, loading, error } = useSemanticQuery();
 *
 * const handleSearch = (question: string) => {
 *   mutate(question, teamId, userId);
 * };
 * ```
 */
export function useSemanticQuery(): SemanticQueryState {
  const api = useRagApi();
  const [data, setData] = useState<RagQueryResponse | undefined>(undefined);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const mutate = useCallback(
    async (question: string, teamId?: string, userId?: string) => {
      setLoading(true);
      setError(null);
      try {
        const result = await api.submitQuery({
          question,
          ...(teamId !== undefined && { teamId }),
          ...(userId !== undefined && { userId }),
        });
        setData(result);
      } catch (err: unknown) {
        setError(err instanceof Error ? err.message : "Unexpected error");
        setData(undefined);
      } finally {
        setLoading(false);
      }
    },
    [api],
  );

  return { mutate, data, loading, error };
}

/**
 * PreLockValidationPanel — shows hard errors and soft warnings before locking.
 */
import { CheckCircle2, XCircle, AlertTriangle } from "lucide-react";
import { AiLintPanel } from "../ai/AiLintPanel.js";
import { useHostBridge } from "../../host/HostProvider.js";
import type { LockValidationError, CommitResponse } from "../../api/planTypes.js";
import { derivePreLockSoftWarnings, getEffectivePreLockErrors } from "./lockValidation.js";

export interface PreLockValidationPanelProps {
  readonly errors: LockValidationError[];
  readonly commits: CommitResponse[];
  readonly isLoading?: boolean;
}

export function PreLockValidationPanel({ errors, commits, isLoading = false }: PreLockValidationPanelProps) {
  const bridge = useHostBridge();
  const userId = bridge.context.authenticatedUser.id;
  const effectiveErrors = getEffectivePreLockErrors(commits, errors);
  const softWarnings = derivePreLockSoftWarnings(commits);
  // Get planId from first commit (all commits share the same planId)
  const planId = commits.length > 0 && commits[0] ? commits[0].planId : null;

  if (isLoading) {
    return (
      <div data-testid="pre-lock-validation-loading" className="rounded-default border border-border bg-background p-3 text-sm text-muted">
        Validating…
      </div>
    );
  }

  const hasErrors = effectiveErrors.length > 0;
  const hasWarnings = softWarnings.length > 0;

  return (
    <div data-testid="pre-lock-validation-panel" className="flex flex-col gap-3">
      {/* All-clear */}
      {!hasErrors && !hasWarnings && (
        <div data-testid="pre-lock-validation-ok" className="flex items-center gap-2 rounded-default border border-foreground/20 bg-foreground/5 px-3 py-2.5 text-sm text-foreground">
          <CheckCircle2 className="h-4 w-4 shrink-0" aria-hidden="true" />
          All validation checks passed. Your plan is ready to lock.
        </div>
      )}

      {/* Hard errors */}
      {hasErrors && (
        <div data-testid="pre-lock-hard-errors" className="rounded-default border border-neutral-300 bg-neutral-100 p-3">
          <p className="m-0 mb-2 flex items-center gap-1.5 text-sm font-bold text-foreground">
            <XCircle className="h-4 w-4 shrink-0" aria-hidden="true" />
            Hard Errors — must be resolved before locking
          </p>
          <ul className="m-0 pl-5 flex flex-col gap-1">
            {effectiveErrors.map((err, i) => (
              <li key={`${err.field}-${i}`} data-testid="hard-error-item" className="text-xs text-foreground">
                <strong>{err.field}:</strong> {err.message}
              </li>
            ))}
          </ul>
        </div>
      )}

      {/* Soft warnings */}
      {hasWarnings && (
        <div data-testid="pre-lock-soft-warnings" className="rounded-default border border-neutral-200 bg-neutral-50 p-3">
          <p className="m-0 mb-2 flex items-center gap-1.5 text-sm font-bold text-muted">
            <AlertTriangle className="h-4 w-4 shrink-0" aria-hidden="true" />
            Soft Warnings — informational, will not block lock
          </p>
          <ul className="m-0 pl-5 flex flex-col gap-1">
            {softWarnings.map((warn, i) => (
              <li key={i} data-testid="soft-warning-item" className="text-xs text-muted">{warn}</li>
            ))}
          </ul>
        </div>
      )}

      {/* AI lint — real integration replacing the placeholder */}
      {planId && (
        <AiLintPanel planId={planId} userId={userId} />
      )}
      {!planId && (
        <div data-testid="pre-lock-ai-lint-placeholder" className="flex items-center gap-2 rounded-default border border-dashed border-border bg-background/60 px-3 py-2.5 text-xs text-muted italic">
          AI commit quality hints will appear once commits are added
        </div>
      )}
    </div>
  );
}

/**
 * AnswerRenderer — renders LLM answer text with lightweight markdown support.
 *
 * Handles:
 *   - **bold** → <strong>
 *   - \n\n  → paragraph breaks
 *   - \n    → line breaks within a paragraph
 *   - "quoted commit titles" → monospace highlighted spans
 *   - Chess piece names (KING/QUEEN/ROOK/BISHOP/KNIGHT/PAWN) → styled badges
 *   - Bullet lists (lines starting with - or •)
 *   - Percentages and point values → highlighted
 *
 * No external dependencies. Pure string → JSX transformation.
 */
import { type ReactNode } from "react";
import { cn } from "../../lib/utils.js";

// ── Chess piece rendering ─────────────────────────────────────────────────

const CHESS_GLYPHS: Record<string, string> = {
  KING: "♔", QUEEN: "♕", ROOK: "♖", BISHOP: "♗", KNIGHT: "♘", PAWN: "♙",
};

const CHESS_SHADES: Record<string, string> = {
  KING: "var(--chess-king)", QUEEN: "var(--chess-queen)", ROOK: "var(--chess-rook)",
  BISHOP: "var(--chess-bishop)", KNIGHT: "var(--chess-knight)", PAWN: "var(--chess-pawn)",
};

// ── Inline token parser ──────────────────────────────────────────────────

type InlineToken =
  | { type: "text"; value: string }
  | { type: "bold"; value: string }
  | { type: "chess"; piece: string }
  | { type: "commit-title"; value: string }
  | { type: "metric"; value: string; unit: string };

function tokenizeInline(text: string): InlineToken[] {
  const tokens: InlineToken[] = [];
  // Combined regex for all inline patterns
  // Order matters: bold first, then commit titles, then chess pieces, then metrics
  const pattern =
    /(\*\*(.+?)\*\*)|("([^"]{3,60})")|(\b(KING|QUEEN|ROOK|BISHOP|KNIGHT|PAWN)\b)|(\b(\d+(?:\.\d+)?)(pts?|%)\b)/g;

  let lastIndex = 0;
  let match: RegExpExecArray | null;

  while ((match = pattern.exec(text)) !== null) {
    // Push preceding plain text
    if (match.index > lastIndex) {
      tokens.push({ type: "text", value: text.slice(lastIndex, match.index) });
    }

    if (match[1]) {
      // **bold**
      tokens.push({ type: "bold", value: match[2]! });
    } else if (match[3]) {
      // "commit title"
      tokens.push({ type: "commit-title", value: match[4]! });
    } else if (match[5]) {
      // CHESS PIECE
      tokens.push({ type: "chess", piece: match[6]! });
    } else if (match[7]) {
      // 5pts, 85%
      tokens.push({ type: "metric", value: match[8]!, unit: match[9]! });
    }

    lastIndex = match.index + match[0].length;
  }

  // Trailing text
  if (lastIndex < text.length) {
    tokens.push({ type: "text", value: text.slice(lastIndex) });
  }

  return tokens;
}

function renderInlineTokens(tokens: InlineToken[]): ReactNode[] {
  return tokens.map((token, i) => {
    switch (token.type) {
      case "text":
        return <span key={i}>{token.value}</span>;
      case "bold":
        return (
          <strong key={i} className="font-bold text-foreground">
            {token.value}
          </strong>
        );
      case "chess":
        return (
          <span
            key={i}
            className="inline-flex items-center gap-0.5 px-1 py-px text-[0.65rem] font-bold tracking-wider"
            style={{ color: CHESS_SHADES[token.piece] }}
          >
            <span className="text-xs">{CHESS_GLYPHS[token.piece]}</span>
            {token.piece}
          </span>
        );
      case "commit-title":
        return (
          <span
            key={i}
            className="font-medium text-foreground bg-muted-bg px-1 py-px border border-border text-[0.8em]"
          >
            {token.value}
          </span>
        );
      case "metric":
        return (
          <span key={i} className="font-bold text-foreground tabular-nums">
            {token.value}
            <span className="text-muted text-[0.85em]">{token.unit}</span>
          </span>
        );
      default:
        return null;
    }
  });
}

// ── Block-level parser ───────────────────────────────────────────────────

type Block =
  | { type: "paragraph"; content: string }
  | { type: "list"; items: string[] }
  | { type: "heading"; content: string };

function parseBlocks(text: string): Block[] {
  const blocks: Block[] = [];
  const paragraphs = text.split(/\n\n+/);

  for (const para of paragraphs) {
    const trimmed = para.trim();
    if (!trimmed) continue;

    const lines = trimmed.split("\n");

    // Check if this is a list (all lines start with - or • or *)
    const isListBlock = lines.length > 1 && lines.every(
      (l) => /^\s*[-•*]\s/.test(l) || l.trim() === "",
    );

    if (isListBlock) {
      blocks.push({
        type: "list",
        items: lines
          .map((l) => l.replace(/^\s*[-•*]\s*/, "").trim())
          .filter(Boolean),
      });
    } else {
      // Join lines within a paragraph (single \n → space or linebreak)
      blocks.push({ type: "paragraph", content: trimmed });
    }
  }

  return blocks;
}

// ── Main component ───────────────────────────────────────────────────────

interface AnswerRendererProps {
  text: string;
  className?: string;
}

export function AnswerRenderer({ text, className }: AnswerRendererProps) {
  const blocks = parseBlocks(text);

  return (
    <div
      className={cn("flex flex-col gap-2 text-sm leading-relaxed", className)}
      data-testid="rag-answer-text"
    >
      {blocks.map((block, i) => {
        switch (block.type) {
          case "paragraph": {
            // Handle inline \n within a paragraph
            const lines = block.content.split("\n");
            return (
              <p key={i} className="m-0">
                {lines.map((line, j) => (
                  <span key={j}>
                    {j > 0 && <br />}
                    {renderInlineTokens(tokenizeInline(line))}
                  </span>
                ))}
              </p>
            );
          }
          case "list":
            return (
              <ul key={i} className="m-0 pl-4 flex flex-col gap-1">
                {block.items.map((item, j) => (
                  <li key={j} className="text-sm list-disc list-outside">
                    {renderInlineTokens(tokenizeInline(item))}
                  </li>
                ))}
              </ul>
            );
          case "heading":
            return (
              <h4 key={i} className="m-0 text-sm font-bold">
                {renderInlineTokens(tokenizeInline(block.content))}
              </h4>
            );
          default:
            return null;
        }
      })}
    </div>
  );
}

/**
 * Thumbs up / thumbs down feedback buttons for AI suggestions.
 * Records feedback via POST /api/ai/feedback.
 */
import { useState, useCallback } from "react";
import { ThumbsUp, ThumbsDown } from "lucide-react";
import { Button } from "../ui/Button.js";
import { cn } from "../../lib/utils.js";
import { useAiApi } from "../../api/aiHooks.js";
import { useHostBridge } from "../../host/HostProvider.js";
import type { FeedbackAction } from "../../api/aiApi.js";

interface AiFeedbackButtonsProps {
  suggestionId: string;
  className?: string;
}

export function AiFeedbackButtons({ suggestionId, className }: AiFeedbackButtonsProps) {
  const aiApi = useAiApi();
  const bridge = useHostBridge();
  const userId = bridge.context.authenticatedUser.id;
  const [submitted, setSubmitted] = useState<FeedbackAction | null>(null);

  const handleFeedback = useCallback(
    async (action: FeedbackAction) => {
      try {
        await aiApi.recordFeedback({ suggestionId, userId, action });
        setSubmitted(action);
      } catch {
        // Non-critical — don't block the UI
      }
    },
    [aiApi, suggestionId, userId],
  );

  if (submitted) {
    return (
      <span className={cn("text-xs text-muted italic", className)}>
        {submitted === "ACCEPTED" ? "Thanks! 👍" : "Noted 👎"}
      </span>
    );
  }

  return (
    <span className={cn("inline-flex gap-1", className)}>
      <Button
        variant="ghost"
        size="icon"
        onClick={() => void handleFeedback("ACCEPTED")}
        aria-label="Helpful suggestion"
        className="h-6 w-6 text-muted hover:text-foreground"
        data-testid="ai-feedback-accept"
      >
        <ThumbsUp className="h-3.5 w-3.5" />
      </Button>
      <Button
        variant="ghost"
        size="icon"
        onClick={() => void handleFeedback("DISMISSED")}
        aria-label="Not helpful"
        className="h-6 w-6 text-muted hover:text-foreground"
        data-testid="ai-feedback-dismiss"
      >
        <ThumbsDown className="h-3.5 w-3.5" />
      </Button>
    </span>
  );
}

